import React from "react";
import { Settings as SettingsIcon } from "lucide-react";

export function SettingsPage() {
  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-white">Settings</h1>
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-20 flex flex-col items-center text-center">
        <SettingsIcon className="w-16 h-16 text-[#39FF14] mb-4 opacity-20" />
        <h2 className="text-xl font-bold text-white">System Preferences</h2>
        <p className="text-gray-400 max-w-xs mt-2">Configure app settings and staff permissions.</p>
      </div>
    </div>
  );
}
